B.Wz=new A.l(2001,4,2,"\uba54\uc774\uc800\ub9ac\uadf8","\uc774\uce58\ub85c, \uc77c\ubcf8\uc778 \uc57c\uc218 \uccab \ube45\ub9ac\uadf8 \ub370\ubdd4","\uc77c\ubcf8 \uc2a4\ud0c0 \uc774\uce58\ub85c\uac00 \uc2dc\uc560\ud2c0\uc5d0\uc11c \uba54\uc774\uc800\ub9ac\uadf8\uc5d0 \ub370\ubdd4\ud588\ub2e4. \uc544\uc2dc\uc544 \uc120\uc218\uc758 \uc0c8 \uae38\uc774 \uc5f4\ub838\ub2e4.","\uac80\uc99d\ub418\uc9c0 \uc54a\uc740 \ub3c4\uc804\uc774 \uc0c8 \uc2dc\uc7a5\uc744 \uc5fd\ub2c8\ub2e4.",B.p)
B.Yy=new A.l(2001,4,3,"\ud55c\uc77c \uac08\ub4f1","\uc77c\ubcf8, \uc5ed\uc0ac \uc65c\uace1 \uad50\uacfc\uc11c \uac80\uc815 \ud1b5\uacfc","\uc77c\ubcf8 \uc815\ubd80\uac00 \uacfc\uac70\uc0ac\ub97c \ubbf8\ud654\ud55c \uad50\uacfc\uc11c\ub97c \uac80\uc815 \ud1b5\uacfc\uc2dc\ucf30\ub2e4. \ud55c\xb7\uc77c \uad00\uacc4\uac00 \uc5bc\uc5b4\ubd99\uc5c8\ub2e4.","\uc774\uc6c3 \ub098\ub77c\uc640\uc758 \uac10\uc815\uc740 \uad50\uc5ed\uacfc \uc5ec\ub860\uc5d0 \uc2a4\uba70\ub4ed\ub2c8\ub2e4.",B.q)
B.V2=new A.l(2001,4,10,"\uad6c\uc870\uc870\uc815 \uc9c4\ud1b5","\ub300\uc6b0\ucc28 \ubd80\ud3c9\uacf5\uc7a5, \uc815\ub9ac\ud574\uace0 \ub193\uace0 \ucda9\ub3cc","\ub9e4\uac01\uc744 \uc55e\ub454 \ub300\uc6b0\uc790\ub3d9\ucc28\uc5d0\uc11c \ub300\uaddc\ubaa8 \uc815\ub9ac\ud574\uace0\uc5d0 \ubc18\ubc1c\ud558\ub294 \ucda9\ub3cc\uc774 \ubc8c\uc5b4\uc84c\ub2e4. \uc7ac\ubc8c \uad6c\uc870\uc870\uc815\uc758 \uc544\ud514\uc774 \ub4dc\ub7ec\ub0ac\ub2e4.","\uad6c\uc870\uc870\uc815\uc740 \uc22b\uc790 \ub4a4\uc5d0 \uc0ac\ub78c\uc774 \uc788\uc2b5\ub2c8\ub2e4.",B.q)
B.XA=new A.l(2001,4,23,"1\ubd84\uae30 \uc2e4\uc801","\uc0bc\uc131\uc804\uc790, \ubc18\ub3c4\uccb4 \ubd88\ud669\uc5d0\ub3c4 1\ubd84\uae30 \ud751\uc790","\uba54\ubaa8\ub9ac \uac12\uc774 \uae09\ub77d\ud558\ub294 \uc640\uc911\uc5d0\ub3c4 \uc0bc\uc131\uc804\uc790\uac00 \ubd84\uae30 \ud751\uc790\ub97c \ub0c8\ub2e4. \uc704\uae30 \uc18d \uccb4\ub825\uc774 \ud655\uc778\ub410\ub2e4.","\ubd88\ud669\uc740 \uac15\ud55c \uae30\uc5c5\uacfc \uc57d\ud55c \uae30\uc5c5\uc744 \uac08\ub77c\ub193\uc2b5\ub2c8\ub2e4.",B.I)
B.W8=new A.l(2001,4,26,"\uc77c\ubcf8 \ucd1d\ub9ac","\uace0\uc774\uc988\ubbf8 \uc900\uc774\uce58\ub85c, \uc77c\ubcf8 \ucd1d\ub9ac \ucde8\uc784","\uac1c\ud601\uc744 \ub0b4\uac74 \uace0\uc774\uc988\ubbf8 \ub0b4\uac01\uc774 \ucd9c\ubc94\ud588\ub2e4. \uc774\uc6c3 \uc77c\ubcf8\uc758 \uc815\uce58 \uc9c0\ud615\uc774 \ubc14\ub010\ub2e4.","\uc606 \ub098\ub77c \uc9c0\ub3c4\uc790\uac00 \ubc14\ub00c\uba74 \ud658\uc728\uacfc \uc678\uad50\ub3c4 \ucd9c\ub801\uc785\ub2c8\ub2e4.",B.p)
B.U0=new A.l(2001,4,28,"\uc6b0\uc8fc \uad00\uad11","\ub370\ub2c8\uc2a4 \ud2f0\ud1a0, \ucd5c\ucd08\uc758 \ubbfc\uac04 \uc6b0\uc8fc \uad00\uad11\uac1d","\ubbf8\uad6d \uc0ac\uc5c5\uac00\uac00 \uc790\ube44\ub85c \uc6b0\uc8fc\uc815\uac70\uc7a5\uc744 \ub2e4\ub140\uc654\ub2e4. \uc6b0\uc8fc\uac00 \uad00\uad11\uc758 \uc601\uc5ed\uc73c\ub85c \ub4e4\uc5b4\uc654\ub2e4.","\uc624\ub298\uc758 \uc0ac\uce58\uac00 \ub0b4\uc77c\uc758 \uc0b0\uc5c5\uc774 \ub418\uae30\ub3c4 \ud569\ub2c8\ub2e4.",B.p)
B.XU=new A.l(2001,5,18,"\uc560\ub2c8\uba54\uc774\uc158","\ub4dc\ub9bc\uc6cd\uc2a4 '\uc288\ub809' \uac1c\ubd09","\ub3d9\ud654\ub97c \ub4a4\uc9d1\uc740 3D \uc560\ub2c8\uba54\uc774\uc158\uc774 \uac1c\ubd09\ud574 \ud070 \uc778\uae30\ub97c \ub04c\uc5c8\ub2e4. \ud53d\uc0ac\uc640\uc758 \uacbd\uc7c1\uc774 \ub728\uac70\uc6cc\uc9c4\ub2e4.","\ucf58\ud150\uce20\ub294 \ud55c \ubc88 \ub9cc\ub4e4\uc5b4 \uc624\ub798 \ud30c\ub294 \uc790\uc0b0\uc785\ub2c8\ub2e4.",B.x)
B.X6=new A.l(2001,5,19,"\uccab \ub9e4\uc7a5","\uc560\ud50c, \uccab \uc624\ud504\ub77c\uc778 \ub9e4\uc7a5 \uc5f4\ub2e4","\uc560\ud50c\uc774 \ubbf8\uad6d\uc5d0 \uc9c1\uc601 \ub9e4\uc7a5 1\ud638\uc810\uc744 \uc5f4\uc5c8\ub2e4. \uc81c\ud488\uc744 \uc9c1\uc811 \ub9cc\uc9c0\uac8c \ud558\ub294 \uc0c8 \uc720\ud1b5 \uc2e4\ud5d8\uc774 \uc2dc\uc791\ub410\ub2e4.","\uc9c1\uc811 \ubcf4\uc5ec\uc8fc\ub294 \uc720\ud1b5, \ucc98\uc74c\uc5d4 \ubb34\ubaa8\ud574 \ubcf4\uc600\uc2b5\ub2c8\ub2e4.",B.x)
B.XX=new A.l(2001,5,24,"\uc0b0\uc545","15\uc138 \uc170\ub974\ud30c, \ucd5c\uc5f0\uc18c \uc5d0\ubca0\ub808\uc2a4\ud2b8 \ub4f1\uc815","\ub124\ud314 \uc18c\ub144\uc774 \uc138\uacc4 \ucd5c\uace0\ubd09\uc5d0 \ucd5c\uc5f0\uc18c\ub85c \uc62c\ub790\ub2e4. \ud55c\uacc4\uc5d0 \ub300\ud55c \ud1b5\ub150\uc774 \uae68\uc84c\ub2e4.","\uae30\ub85d\uc740 \uae68\uc9c0\ub77c\uace0 \uc788\uc2b5\ub2c8\ub2e4.",B.p)
